DROP TABLE IF EXISTS "XXL_JOB_GROUP";
CREATE TABLE "XXL_JOB_GROUP" (
  "ID" INTEGER IDENTITY(1,1) NOT NULL,
  "APP_NAME" VARCHAR2(64) NOT NULL,
  -- MySQL varchar(12) uses character length; DM VARCHAR2 length is byte-sensitive, so widen this Chinese title field.
  "TITLE" VARCHAR2(64) NOT NULL,
  "ADDRESS_TYPE" TINYINT DEFAULT 0 NOT NULL,
  "ADDRESS_LIST" CLOB NULL,
  "UPDATE_TIME" TIMESTAMP NULL,
  CONSTRAINT "PK_XXL_JOB_GROUP" PRIMARY KEY ("ID")
);
COMMENT ON COLUMN "XXL_JOB_GROUP"."APP_NAME" IS '执行器AppName';
COMMENT ON COLUMN "XXL_JOB_GROUP"."TITLE" IS '执行器名称';
COMMENT ON COLUMN "XXL_JOB_GROUP"."ADDRESS_TYPE" IS '执行器地址类型：0=自动注册、1=手动录入';
COMMENT ON COLUMN "XXL_JOB_GROUP"."ADDRESS_LIST" IS '执行器地址列表，多地址逗号分隔';

SET IDENTITY_INSERT "XXL_JOB_GROUP" ON;
