DROP TABLE IF EXISTS "XXL_JOB_LOG_REPORT";
CREATE TABLE "XXL_JOB_LOG_REPORT" (
  "ID" INTEGER IDENTITY(1,1) NOT NULL,
  "TRIGGER_DAY" TIMESTAMP NULL,
  "RUNNING_COUNT" INTEGER DEFAULT 0 NOT NULL,
  "SUC_COUNT" INTEGER DEFAULT 0 NOT NULL,
  "FAIL_COUNT" INTEGER DEFAULT 0 NOT NULL,
  "UPDATE_TIME" TIMESTAMP NULL,
  CONSTRAINT "PK_XXL_JOB_LOG_REPORT" PRIMARY KEY ("ID")
);
COMMENT ON COLUMN "XXL_JOB_LOG_REPORT"."TRIGGER_DAY" IS '调度-时间';
COMMENT ON COLUMN "XXL_JOB_LOG_REPORT"."RUNNING_COUNT" IS '运行中-日志数量';
COMMENT ON COLUMN "XXL_JOB_LOG_REPORT"."SUC_COUNT" IS '执行成功-日志数量';
COMMENT ON COLUMN "XXL_JOB_LOG_REPORT"."FAIL_COUNT" IS '执行失败-日志数量';
CREATE UNIQUE INDEX "I_TRIGGER_DAY" ON "XXL_JOB_LOG_REPORT" ("TRIGGER_DAY");

SET IDENTITY_INSERT "XXL_JOB_LOG_REPORT" ON;
